We’re now using a for loop to iterate through each data frame and create levels of a new variable called status. I’m choosing to make status a factor instead of a character variable since we have discrete, unchanging levels.

# create status column
treatment_list$treatment$status &lt;- factor(character(nrow(treatment_list$treatment)),
                                          levels = (c("Optimal", "Borderline", "High")),
                                          ordered = TRUE)
treatment_list$placebo$status &lt;- factor(character(nrow(treatment_list$placebo)),
                                        levels = (c("Optimal", "Borderline", "High")),
                                        ordered = TRUE)

# assign levels of status to each obs in treatment df
for(i in 1:nrow(treatment_list$treatment)) {
  if(treatment_list$treatment$post_bp[i] &gt; 130) {
    treatment_list$treatment$status[i] &lt;- "High"
  } else if(treatment_list$treatment$post_bp[i] &gt;= 120) {
    treatment_list$treatment$status[i] &lt;- "Borderline"
  } else {
    treatment_list$treatment$status[i] &lt;- "Optimal"
  }
}

